// Code to get stores associated with DXS Service account
// This sample code writes the response to a file named GetStoresResponse.json in the same directory as the script.
/* 
Tested with Versions:
Node v20.11.1
axios v1.6.7
*/
const axios = require('axios');
const fs = require('fs').promises;

// This API uses v1 of the HME DXS Management API, please refer on the left for the parameter details
// Change the values of the following variables to your own values
const apiParams = {
  baseUrl: 'https://api.hmecloud.com/dxsmgmt/v1/store/list/default',
  service_account: 'Service Account Example',
  auth_key: '11111111-2222-3333-4444-555555555555',
  limit: 1000,
  offset: 0,
};

// Function to make the HTTP GET request
async function makeGetRequest(params) {
  const apiUrl = `${params.baseUrl}?Limit=${params.limit}&Offset=${params.offset}`;
  const headers = {
    'service-account': params.service_account,
    'auth-key': params.auth_key,
  };

  try {
    const response = await axios.get(apiUrl, { headers });

    // Write the response to a file
    await fs.writeFile('GetStoresResponse.json', JSON.stringify(response.data, null, 2));

  } catch (error) {
    // Handle any errors that occurred during the request
    console.error('Error:');
    console.error('Status Code:',error.response.status);
    console.error('Message:',error.response.data);
  }
}

// Calling the function to make the request
makeGetRequest(apiParams);

