// Code to get raw car data for a specified service account
// This sample code writes the response to a file named GetRCDResponse.json in the same directory as the script.
/* 
Tested with Versions:
Node v20.11.1
axios v1.6.7
*/
const axios = require('axios');
const fs = require('fs').promises;

// This API uses v1 of the HME DXS Management API, please refer on the left for the parameter details
// Change the values of the following variables to your own values
const apiParams = {
  baseUrl: 'https://api.hmecloud.com/dxs/v1/rcd/report',
  service_account: 'Service Account Example',
  auth_key: '11111111-2222-3333-4444-555555555555',
  account_email: 'test@test.com',
  includePullOuts: true,
  storeNumberList: ["123456"],
  includeIndependents: false,
  startDateTime: '2024-01-01T12:00:00.000Z',
  endDateTime: '2024-01-02T12:00:08.000Z',
  limit: 1000,
  offset: 0
};

// Function to make the HTTP GET request
async function makeGetRequest(params) {
  const apiUrl = `${params.baseUrl}?IncludePullOuts=${params.includePullOuts}&StoreNumberList=${encodeURIComponent(JSON.stringify(params.storeNumberList))}&IncludeIndependents=${params.includeIndependents}&StartDateTime=${params.startDateTime}&EndDateTime=${params.endDateTime}&limit=${params.limit}&offset=${params.offset}`;
  const headers = {
    'service-account': params.service_account,
    'auth-key': params.auth_key,
    'account-email': params.account_email
  };

  try {
    const response = await axios.get(apiUrl, { headers });

    // Write the response to a file
    await fs.writeFile('GetRCDResponse.json', JSON.stringify(response.data, null, 2));

  } catch (error) {
    // Handle any errors that occurred during the request
    console.error('Error:');
    console.error('Status Code:',error.response.status);
    console.error('Message:',error.response.data);
  }
}

// Calling the function to make the request
makeGetRequest(apiParams);
